@* Displays a single task with move-left/move-right buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center">
            <div>
                <span class="badge @PriorityClass">@Task.Priority</span>
                <span class="text-muted small ms-1">@Task.DueDate.ToString("MMM dd")</span>
            </div>
            <div>
                @if (ShowMoveLeft)
                {
                    <button class="btn btn-sm btn-outline-secondary py-0 px-1 me-1"
                            @onclick="OnMoveLeft"
                            disabled="@IsMoving">
                        &laquo;
                    </button>
                }
                @if (ShowMoveRight)
                {
                    <button class="btn btn-sm btn-outline-secondary py-0 px-1"
                            @onclick="OnMoveRight"
                            disabled="@IsMoving">
                        &raquo;
                    </button>
                }
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }
    [Parameter] public bool IsMoving { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form for creating a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title"
                   @bind="title" @bind:event="oninput" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                   @bind="assignee" @bind:event="oninput" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-sm btn-primary" @onclick="HandleSave" disabled="@isSaving">
                @(isSaving ? "Saving…" : "Save")
            </button>
            <button class="btn btn-sm btn-outline-secondary" @onclick="OnCancel" disabled="@isSaving">
                Cancel
            </button>
        </div>
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="text-danger small mt-1">@errorMessage</div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? errorMessage;

    private async Task HandleSave()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(title))
        {
            errorMessage = "Title is required.";
            return;
        }

        isSaving = true;
        try
        {
            await OnSave.InvokeAsync((title, assignee, priority, dueDate));
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isSaving = false;
        }
    }
}

@* Summary stats bar showing task counts and overdue count *@

<div class="d-flex flex-wrap gap-3 mb-3 p-2 bg-light rounded">
    <span class="badge bg-secondary fs-6">Total: @Total</span>
    <span class="badge bg-primary fs-6">To Do: @ToDo</span>
    <span class="badge bg-info text-dark fs-6">In Progress: @InProgress</span>
    <span class="badge bg-success fs-6">Done: @Done</span>
    <span class="badge bg-danger fs-6">Overdue: @Overdue</span>
</div>

@code {
    [Parameter] public int Total { get; set; }
    [Parameter] public int ToDo { get; set; }
    [Parameter] public int InProgress { get; set; }
    [Parameter] public int Done { get; set; }
    [Parameter] public int Overdue { get; set; }
}

@* Search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title…"
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> SearchTextChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? string.Empty;
        await SearchTextChanged.InvokeAsync(value);
    }
}

@* A single Kanban column displaying its tasks and an add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body overflow-auto" style="max-height: 70vh;">
            @foreach (var task in Tasks)
            {
                var taskId = task.Id;
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          IsMoving="movingTaskId == taskId"
                          OnMoveLeft="() => HandleMove(taskId, MoveDirection.Left)"
                          OnMoveRight="() => HandleMove(taskId, MoveDirection.Right)" />
            }

            @if (showForm)
            {
                <AddTaskForm OnSave="HandleSave" OnCancel="() => showForm = false" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    public enum MoveDirection { Left, Right }

    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(int TaskId, MoveDirection Direction)> OnMoveTask { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnAddTask { get; set; }

    private bool showForm;
    private int? movingTaskId;

    private async Task HandleMove(int taskId, MoveDirection direction)
    {
        movingTaskId = taskId;
        try
        {
            await OnMoveTask.InvokeAsync((taskId, direction));
        }
        finally
        {
            movingTaskId = null;
        }
    }

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        await OnAddTask.InvokeAsync(data);
        showForm = false;
    }
}

