@* Displays a single task with move-left/move-right buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center">
            <div>
                <span class="badge @PriorityClass">@Task.Priority</span>
                <span class="text-muted small ms-1">@Task.DueDate.ToString("MMM dd")</span>
            </div>
            <div>
                @if (ShowMoveLeft)
                {
                    <button class="btn btn-sm btn-outline-secondary py-0 px-1 me-1"
                            @onclick="OnMoveLeft"
                            disabled="@IsMoving">
                        &laquo;
                    </button>
                }
                @if (ShowMoveRight)
                {
                    <button class="btn btn-sm btn-outline-secondary py-0 px-1"
                            @onclick="OnMoveRight"
                            disabled="@IsMoving">
                        &raquo;
                    </button>
                }
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }
    [Parameter] public bool IsMoving { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form for creating a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title"
                   @bind="title" @bind:event="oninput" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                   @bind="assignee" @bind:event="oninput" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-sm btn-primary" @onclick="HandleSave" disabled="@isSaving">
                @(isSaving ? "Saving…" : "Save")
            </button>
            <button class="btn btn-sm btn-outline-secondary" @onclick="OnCancel" disabled="@isSaving">
                Cancel
            </button>
        </div>
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="text-danger small mt-1">@errorMessage</div>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? errorMessage;

    private async Task HandleSave()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(title))
        {
            errorMessage = "Title is required.";
            return;
        }

        isSaving = true;
        try
        {
            await OnSave.InvokeAsync((title, assignee, priority, dueDate));
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isSaving = false;
        }
    }
}

