@page "/board"
@using sv_d0e0113adffd4786b10e7045556c049d.Components.Board
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Total="filteredTasks.Count"
                ToDo="todoTasks.Count"
                InProgress="inProgressTasks.Count"
                Done="doneTasks.Count"
                Overdue="filteredTasks.Count(t => t.DueDate < DateTime.Today)" />

    <TaskSearchBar SearchText="@searchText" SearchTextChanged="HandleSearchChanged" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="todoTasks"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
