 @code {
     private const string StatusToDo = "To Do";
     private const string StatusInProgress = "In Progress";
     private const string StatusDone = "Done";
     private static readonly string[] Columns = [StatusToDo, StatusInProgress, StatusDone];

     private List<TaskItem> allTasks = new();
     private string searchText = string.Empty;
     private bool isLoading = true;
     private string? errorMessage;

     private List<TaskItem> filteredTasks => allTasks
         .Where(t => string.IsNullOrWhiteSpace(searchText)
             || t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase))
         .ToList();

     private List<TaskItem> todoTasks => filteredTasks.Where(t => t.Status == "To Do").ToList();
     private List<TaskItem> inProgressTasks => filteredTasks.Where(t => t.Status == "In Progress").ToList();
     private List<TaskItem> doneTasks => filteredTasks.Where(t => t.Status == "Done").ToList();

     protected override async Task OnInitializedAsync()
     {
         await LoadTasks();
     }

     private async Task LoadTasks()
     {
         isLoading = true;
         errorMessage = null;

         try
         {
             allTasks = await TaskService.GetAllTasksAsync();
         }
         catch (Exception ex)
         {
             errorMessage = ex.Message;
         }
         finally
         {
             isLoading = false;
         }
     }

     private void HandleSearchChanged(string value)
     {
         searchText = value;
     }

     private async Task HandleMove(int taskId, KanbanColumn.MoveDirection direction)
     {
         var task = allTasks.FirstOrDefault(t => t.Id == taskId);
         if (task is null) return;

         var currentIndex = Array.IndexOf(Columns, task.Status);
         var newIndex = direction == KanbanColumn.MoveDirection.Left
             ? currentIndex - 1
             : currentIndex + 1;

         if (newIndex < 0 || newIndex >= Columns.Length) return;

         var newStatus = Columns[newIndex];
         await TaskService.UpdateTaskStatusAsync(taskId, newStatus);

         // Replace the immutable record in the list
         var idx = allTasks.FindIndex(t => t.Id == taskId);
         if (idx >= 0)
         {
             allTasks[idx] = task with { Status = newStatus };
         }
     }

     private async Task HandleAdd(
         (string Title, string Assignee, string Priority, DateTime DueDate) data,
         string status)
     {
         var created = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
         // CreateTaskAsync returns a task with default status; ensure it matches the column
         allTasks.Add(created with { Status = status });
     }
 }

